contracts/VeraGigEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IVeraScoreRegistry {
    function updateScore(
        address worker,
        uint16 newScore,
        uint32 tasksCompleted,
        uint32 tasksAccepted,
        uint32 disputesLost,
        uint32 loansRepaidOnTime,
        uint32 ubiClaimStreakDays,
        uint32 earningConsistencyWeeks,
        string calldata trigger
    ) external;
    function getScore(address worker) external view returns (uint16);
}

interface IVeraGigFeeRouter {
    function routeFee(bytes32 taskId, uint256 settlementAmount, address payer) external;
}

contract VeraGigEscrow is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable gDollar;
    IVeraScoreRegistry public scoreRegistry;
    IVeraGigFeeRouter public feeRouter;

    uint256 public constant FEE_BPS = 200; // 2%
    uint256 public constant BPS_DENOM = 10000;

    enum TaskStatus { Open, Assigned, Submitted, Completed, Disputed, Cancelled }

    struct Task {
        bytes32 id;
        address client;
        address worker;
        uint256 rewardWei;
        uint256 deadline;
        TaskStatus status;
        bytes32 deliverableCid;
        uint8 rating;
        bool releaseAsStream;
        uint256 payoutDurationDays;
    }

    mapping(bytes32 => Task) public tasks;
    mapping(bytes32 => bytes32) public disputes; // taskId => disputeId

    event TaskCreated(bytes32 indexed taskId, address indexed client, uint256 rewardWei, uint256 deadline);
    event TaskAssigned(bytes32 indexed taskId, address indexed worker);
    event TaskSubmitted(bytes32 indexed taskId, address indexed worker, bytes32 deliverableCid);
    event TaskCompleted(bytes32 indexed taskId, address indexed worker, uint8 rating);
    event TaskCancelled(bytes32 indexed taskId);
    event DisputeRaised(bytes32 indexed taskId, address indexed raiser, bytes32 disputeId);
    event DisputeResolved(bytes32 indexed taskId, address indexed winner);

    constructor(
        address _gDollar,
        address _scoreRegistry,
        address _feeRouter
    ) Ownable(msg.sender) {
        gDollar = IERC20(_gDollar);
        scoreRegistry = IVeraScoreRegistry(_scoreRegistry);
        feeRouter = IVeraGigFeeRouter(_feeRouter);
    }

    function createTask(
        bytes32 taskId,
        uint256 rewardWei,
        uint256 deadline,
        bool releaseAsStream,
        uint256 payoutDurationDays
    ) external nonReentrant {
        require(tasks[taskId].client == address(0), "Task exists");
        require(deadline > block.timestamp, "Deadline in past");
        require(rewardWei > 0, "Reward required");

        uint256 fee = (rewardWei * FEE_BPS) / BPS_DENOM;
        uint256 totalRequired = rewardWei + fee;

        gDollar.safeTransferFrom(msg.sender, address(this), totalRequired);

        tasks[taskId] = Task({
            id: taskId,
            client: msg.sender,
            worker: address(0),
            rewardWei: rewardWei,
            deadline: deadline,
            status: TaskStatus.Open,
            deliverableCid: bytes32(0),
            rating: 0,
            releaseAsStream: releaseAsStream,
            payoutDurationDays: payoutDurationDays
        });

        emit TaskCreated(taskId, msg.sender, rewardWei, deadline);
    }

    function assignTask(bytes32 taskId, address worker) external {
        Task storage task = tasks[taskId];
        require(task.client == msg.sender, "Not client");
        require(task.status == TaskStatus.Open, "Not open");
        task.worker = worker;
        task.status = TaskStatus.Assigned;
        emit TaskAssigned(taskId, worker);
    }

    function submitDeliverable(bytes32 taskId, bytes32 deliverableCid) external {
        Task storage task = tasks[taskId];
        require(task.worker == msg.sender, "Not worker");
        require(task.status == TaskStatus.Assigned, "Not assigned");
        task.deliverableCid = deliverableCid;
        task.status = TaskStatus.Submitted;
        emit TaskSubmitted(taskId, msg.sender, deliverableCid);
    }

    function approveAndRelease(bytes32 taskId, uint8 rating) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.client == msg.sender, "Not client");
        require(task.status == TaskStatus.Submitted, "Not submitted");
        require(rating >= 1 && rating <= 5, "Rating 1-5");

        task.rating = rating;
        task.status = TaskStatus.Completed;

        uint256 fee = (task.rewardWei * FEE_BPS) / BPS_DENOM;

        // Route platform fee
        gDollar.forceApprove(address(feeRouter), fee);
        feeRouter.routeFee(taskId, task.rewardWei, task.client);

        // Release reward to worker (lump sum — streaming handled off-chain via Superfluid)
        gDollar.safeTransfer(task.worker, task.rewardWei);

        emit TaskCompleted(taskId, task.worker, rating);
    }

    function cancelTask(bytes32 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.client == msg.sender, "Not client");
        require(task.status == TaskStatus.Open, "Can only cancel open tasks");

        task.status = TaskStatus.Cancelled;
        uint256 fee = (task.rewardWei * FEE_BPS) / BPS_DENOM;
        gDollar.safeTransfer(task.client, task.rewardWei + fee);

        emit TaskCancelled(taskId);
    }

    function raiseDispute(bytes32 taskId, bytes32 evidenceCid) external nonReentrant returns (bytes32 disputeId) {
        Task storage task = tasks[taskId];
        require(
            task.client == msg.sender || task.worker == msg.sender,
            "Not party"
        );
        require(
            task.status == TaskStatus.Submitted || task.status == TaskStatus.Assigned,
            "Cannot dispute"
        );

        disputeId = keccak256(abi.encodePacked(taskId, msg.sender, block.timestamp));
        disputes[taskId] = disputeId;
        task.status = TaskStatus.Disputed;

        emit DisputeRaised(taskId, msg.sender, disputeId);
    }

    function resolveDispute(bytes32 taskId, address winner) external onlyOwner nonReentrant {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Disputed, "Not disputed");

        task.status = TaskStatus.Completed;
        uint256 fee = (task.rewardWei * FEE_BPS) / BPS_DENOM;

        gDollar.forceApprove(address(feeRouter), fee);
        feeRouter.routeFee(taskId, task.rewardWei, task.client);
        gDollar.safeTransfer(winner, task.rewardWei);

        emit DisputeResolved(taskId, winner);
    }

    function getTask(bytes32 taskId) external view returns (Task memory) {
        return tasks[taskId];
    }

    function updateContracts(address _scoreRegistry, address _feeRouter) external onlyOwner {
        scoreRegistry = IVeraScoreRegistry(_scoreRegistry);
        feeRouter = IVeraGigFeeRouter(_feeRouter);
    }
}

contracts/VeraGigFeeRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract VeraGigFeeRouter is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public immutable gDollar;

    address public ubiPool;        // VeraCollective Worker Advancement Pool
    address public treasury;       // VeraGig treasury

    uint256 public constant UBI_POOL_PCT = 50;
    uint256 public constant TREASURY_PCT = 50;
    uint256 public constant FEE_BPS = 200; // 2%
    uint256 public constant BPS_DENOM = 10000;

    mapping(address => bool) public authorizedCallers;

    event FeeRouted(
        bytes32 indexed taskId,
        uint256 settlementAmount,
        uint256 ubiContribution,
        uint256 treasuryContribution
    );

    constructor(address _gDollar, address _ubiPool, address _treasury) Ownable(msg.sender) {
        gDollar = IERC20(_gDollar);
        ubiPool = _ubiPool;
        treasury = _treasury;
    }

    modifier onlyAuthorized() {
        require(authorizedCallers[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }

    function setAuthorizedCaller(address caller, bool authorized) external onlyOwner {
        authorizedCallers[caller] = authorized;
    }

    function setAddresses(address _ubiPool, address _treasury) external onlyOwner {
        ubiPool = _ubiPool;
        treasury = _treasury;
    }

    function routeFee(bytes32 taskId, uint256 settlementAmount, address payer) external onlyAuthorized {
        uint256 feeAmount = (settlementAmount * FEE_BPS) / BPS_DENOM;

        gDollar.safeTransferFrom(payer, address(this), feeAmount);

        uint256 ubiContribution = (feeAmount * UBI_POOL_PCT) / 100;
        uint256 treasuryContribution = feeAmount - ubiContribution;

        gDollar.safeTransfer(ubiPool, ubiContribution);
        gDollar.safeTransfer(treasury, treasuryContribution);

        emit FeeRouted(taskId, settlementAmount, ubiContribution, treasuryContribution);
    }
}

contracts/VeraGigLendingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IVeraScoreRegistry {
    function getScore(address worker) external view returns (uint16);
    function getLoanTier(address worker) external view returns (string memory);
}

contract VeraGigLendingPool is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable gDollar;
    IVeraScoreRegistry public scoreRegistry;

    // Loan tier limits in G$ (18 decimals)
    uint256 public constant STARTER_MAX = 50 ether;   // 50 G$
    uint256 public constant BUILDER_MAX = 200 ether;  // 200 G$
    uint256 public constant PRIME_MAX   = 500 ether;  // 500 G$

    // Repayment deduction percentages
    uint8 public constant STARTER_DEDUCTION = 30;
    uint8 public constant BUILDER_DEDUCTION = 20;
    uint8 public constant PRIME_DEDUCTION   = 15;

    struct Loan {
        bytes32 id;
        address worker;
        uint256 principalWei;
        uint256 remainingWei;
        uint8 repaymentDeductionPct;
        uint256 createdAt;
        bool fullyRepaid;
    }

    mapping(address => bytes32) public activeLoanId;
    mapping(bytes32 => Loan) public loans;
    mapping(address => bool) public authorizedRepayers;

    uint256 public totalPoolBalance;

    event LoanIssued(bytes32 indexed loanId, address indexed worker, uint256 amountWei);
    event LoanRepayment(bytes32 indexed loanId, uint256 deductionWei, uint256 remainingWei);
    event LoanFullyRepaid(bytes32 indexed loanId, address indexed worker);
    event PoolDeposit(address indexed depositor, uint256 amountWei);

    constructor(address _gDollar, address _scoreRegistry) Ownable(msg.sender) {
        gDollar = IERC20(_gDollar);
        scoreRegistry = IVeraScoreRegistry(_scoreRegistry);
    }

    modifier onlyAuthorizedRepayer() {
        require(authorizedRepayers[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }

    function setAuthorizedRepayer(address repayer, bool authorized) external onlyOwner {
        authorizedRepayers[repayer] = authorized;
    }

    function deposit(uint256 amountWei) external nonReentrant {
        gDollar.safeTransferFrom(msg.sender, address(this), amountWei);
        totalPoolBalance += amountWei;
        emit PoolDeposit(msg.sender, amountWei);
    }

    function checkEligibility(address worker) external view returns (
        bool isEligible,
        uint256 maxLoanWei,
        uint8 repaymentPct,
        string memory tier,
        string memory reason
    ) {
        if (activeLoanId[worker] != bytes32(0)) {
            return (false, 0, 0, "none", "LOAN_ALREADY_ACTIVE");
        }

        uint16 score = scoreRegistry.getScore(worker);
        tier = scoreRegistry.getLoanTier(worker);

        bytes32 tierHash = keccak256(bytes(tier));
        if (tierHash == keccak256(bytes("prime"))) {
            maxLoanWei = PRIME_MAX;
            repaymentPct = PRIME_DEDUCTION;
        } else if (tierHash == keccak256(bytes("builder"))) {
            maxLoanWei = BUILDER_MAX;
            repaymentPct = BUILDER_DEDUCTION;
        } else if (tierHash == keccak256(bytes("starter"))) {
            maxLoanWei = STARTER_MAX;
            repaymentPct = STARTER_DEDUCTION;
        } else {
            return (false, 0, 0, "none", "INSUFFICIENT_GOOD_SCORE");
        }

        if (totalPoolBalance < maxLoanWei) {
            return (false, 0, 0, tier, "POOL_INSUFFICIENT_LIQUIDITY");
        }

        isEligible = true;
        reason = "";
    }

    function requestLoan(uint256 requestedWei, string calldata purpose) external nonReentrant returns (bytes32 loanId) {
        require(activeLoanId[msg.sender] == bytes32(0), "LOAN_ALREADY_ACTIVE");

        (bool isEligible, uint256 maxLoanWei, uint8 repaymentPct,,) = this.checkEligibility(msg.sender);
        require(isEligible, "Not eligible");
        require(requestedWei <= maxLoanWei, "Exceeds max loan");
        require(totalPoolBalance >= requestedWei, "POOL_INSUFFICIENT_LIQUIDITY");

        loanId = keccak256(abi.encodePacked(msg.sender, block.timestamp, purpose));

        loans[loanId] = Loan({
            id: loanId,
            worker: msg.sender,
            principalWei: requestedWei,
            remainingWei: requestedWei,
            repaymentDeductionPct: repaymentPct,
            createdAt: block.timestamp,
            fullyRepaid: false
        });

        activeLoanId[msg.sender] = loanId;
        totalPoolBalance -= requestedWei;

        gDollar.safeTransfer(msg.sender, requestedWei);
        emit LoanIssued(loanId, msg.sender, requestedWei);
    }

    function processRepayment(
        bytes32 loanId,
        uint256 payoutAmountWei
    ) external onlyAuthorizedRepayer nonReentrant returns (uint256 deductionWei) {
        Loan storage loan = loans[loanId];
        require(!loan.fullyRepaid, "Already repaid");

        deductionWei = (payoutAmountWei * loan.repaymentDeductionPct) / 100;
        if (deductionWei > loan.remainingWei) {
            deductionWei = loan.remainingWei;
        }

        loan.remainingWei -= deductionWei;
        totalPoolBalance += deductionWei;

        emit LoanRepayment(loanId, deductionWei, loan.remainingWei);

        if (loan.remainingWei == 0) {
            loan.fullyRepaid = true;
            activeLoanId[loan.worker] = bytes32(0);
            emit LoanFullyRepaid(loanId, loan.worker);
        }
    }

    function getLoan(bytes32 loanId) external view returns (Loan memory) {
        return loans[loanId];
    }
}

contracts/VeraScoreRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract VeraScoreRegistry is Ownable, ReentrancyGuard {
    struct WorkerScore {
        uint16 score;           // 0–850 composite score
        uint32 lastUpdatedBlock;
        uint32 tasksCompleted;
        uint32 tasksAccepted;
        uint32 disputesLost;
        uint32 loansRepaidOnTime;
        uint32 ubiClaimStreakDays;
        uint32 earningConsistencyWeeks;
    }

    mapping(address => WorkerScore) public scores;
    mapping(address => bool) public authorizedUpdaters;

    event ScoreUpdated(address indexed worker, uint16 oldScore, uint16 newScore, string trigger);
    event UpdaterAuthorized(address indexed updater, bool authorized);

    constructor() Ownable(msg.sender) {}

    modifier onlyAuthorized() {
        require(authorizedUpdaters[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }

    function setAuthorizedUpdater(address updater, bool authorized) external onlyOwner {
        authorizedUpdaters[updater] = authorized;
        emit UpdaterAuthorized(updater, authorized);
    }

    function updateScore(
        address worker,
        uint16 newScore,
        uint32 tasksCompleted,
        uint32 tasksAccepted,
        uint32 disputesLost,
        uint32 loansRepaidOnTime,
        uint32 ubiClaimStreakDays,
        uint32 earningConsistencyWeeks,
        string calldata trigger
    ) external onlyAuthorized {
        uint16 oldScore = scores[worker].score;
        scores[worker] = WorkerScore({
            score: newScore,
            lastUpdatedBlock: uint32(block.number),
            tasksCompleted: tasksCompleted,
            tasksAccepted: tasksAccepted,
            disputesLost: disputesLost,
            loansRepaidOnTime: loansRepaidOnTime,
            ubiClaimStreakDays: ubiClaimStreakDays,
            earningConsistencyWeeks: earningConsistencyWeeks
        });
        emit ScoreUpdated(worker, oldScore, newScore, trigger);
    }

    function getScore(address worker) external view returns (uint16) {
        return scores[worker].score;
    }

    function getLoanTier(address worker) external view returns (string memory) {
        uint16 score = scores[worker].score;
        if (score >= 700) return "prime";
        if (score >= 500) return "builder";
        if (score >= 300) return "starter";
        return "none";
    }

    function getFullProfile(address worker) external view returns (WorkerScore memory) {
        return scores[worker];
    }
}

